import{_ as t,a as n,b as o,c as a,d}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as r}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as i,o as l,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const O=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/ocr.md","filePath":"nl-NL/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"nl-NL/Other/ocr.md"};function g(h,e,u,k,b,m){return l(),s("div",null,[...e[0]||(e[0]=[c('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR haalt tekst uit afbeeldingen, scans en screenshots van documenten.</p><p>Na herkenning kun je het resultaat kopiëren, exporteren als <code>Markdown</code>, <code>PDF</code> of <code>Word</code>, of meerdere formaten samen downloaden als pakket.</p><h2 id="wat-ocr-kan-doen" tabindex="-1">Wat OCR kan doen <a class="header-anchor" href="#wat-ocr-kan-doen" aria-label="Permalink to &quot;Wat OCR kan doen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Functie</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Tekstherkenning in afbeeldingen</td><td>Haalt tekst uit afbeeldingen, screenshots en scans.</td></tr><tr><td>Documentlay-outherkenning</td><td>Beter voor tabellen, formules, stempels en gemengde tekst-afbeeldinglayouts.</td></tr><tr><td>Meerdere diensten</td><td>Ondersteunt Baidu PaddleOCR, Microsoft Azure Vision en Google Vision.</td></tr><tr><td>Resultaten kopiëren</td><td>Kopieer herkende tekst na verwerking.</td></tr><tr><td>Bestanden exporteren</td><td>Exporteer <code>Markdown</code>, <code>PDF</code> en <code>Word</code>.</td></tr><tr><td>Batchverpakking</td><td>Download na herkenning van meerdere bestanden resultaten als pakket.</td></tr></tbody></table><h2 id="configureer-eerst-ocr-diensten" tabindex="-1">Configureer eerst OCR-diensten <a class="header-anchor" href="#configureer-eerst-ocr-diensten" aria-label="Permalink to &quot;Configureer eerst OCR-diensten&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP-geolocatie en OCR" loading="lazy"></p><p>Vul gegevens in voor de diensten die je wilt gebruiken:</p><table tabindex="0"><thead><tr><th>Dienst</th><th>Wat je invult</th><th>Beste keuze voor</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Aanbevolen eerste keuze. Goed voor documenten, afbeeldingen, tabellen en gemengde layouts.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> en <code>Azure Vision API Key</code></td><td>Handig als je al Microsoft-cloudservices gebruikt.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Serviceaccount-<code>JSON</code> wordt alleen gebruikt voor quota-opvraag.</td><td>Handig als je Google Cloud gebruikt.</td></tr></tbody></table><p>Sla op nadat je gegevens hebt ingevuld.</p><p>Voor een eerste test kun je één dienst configureren. Je hebt ze niet alle drie nodig.</p><h2 id="google-vision-instellen" tabindex="-1">Google Vision instellen <a class="header-anchor" href="#google-vision-instellen" aria-label="Permalink to &quot;Google Vision instellen&quot;">​</a></h2><p>Google heeft twee onderdelen:</p><table tabindex="0"><thead><tr><th>Doel</th><th>Vereiste</th></tr></thead><tbody><tr><td>OCR gebruiken</td><td>Schakel <code>Cloud Vision API</code> in en maak daarna een <code>API Key</code>.</td></tr><tr><td>Gebruik opvragen</td><td>Maak een serviceaccount, geef <code>Monitoring Viewer</code> en download daarna de serviceaccount-<code>JSON</code>.</td></tr></tbody></table><p><img src="'+r+'" alt="Google API key en serviceaccount" loading="lazy"></p><h3 id="google-gebruiken-voor-ocr" tabindex="-1">Google gebruiken voor OCR <a class="header-anchor" href="#google-gebruiken-voor-ocr" aria-label="Permalink to &quot;Google gebruiken voor OCR&quot;">​</a></h3><ol><li>Open Google Cloud Console.</li><li>Ga naar <code>APIs &amp; Services</code>.</li><li>Open <code>Library</code>, zoek <code>Cloud Vision API</code> en schakel deze in.</li><li>Ga terug naar <code>Credentials</code>.</li><li>Maak een <code>API Key</code>.</li><li>Open de API Key en kopieer deze.</li><li>Plak deze in <code>Google Vision API Key</code> in ImgBed.</li><li>Sla op.</li></ol><p>Daarna kun je Google Vision kiezen in het OCR-venster.</p><h3 id="google-gebruik-opvragen" tabindex="-1">Google-gebruik opvragen <a class="header-anchor" href="#google-gebruik-opvragen" aria-label="Permalink to &quot;Google-gebruik opvragen&quot;">​</a></h3><p>Quota-opvraag is niet nodig voor herkenning.</p><p>Het toont alleen grofweg hoeveel Google Vision-aanroepen in de laatste 30 dagen zijn gebruikt.</p><ol><li>Open in Google Cloud Console <code>IAM &amp; Admin</code>.</li><li>Open <code>Service Accounts</code>.</li><li>Maak een serviceaccount, bijvoorbeeld <code>vision-monitor</code>.</li><li>Geef dit account de rol <code>Monitoring Viewer</code>.</li><li>Open de details van het serviceaccount en maak een key.</li><li>Kies <code>JSON</code>.</li><li>Download het gegenereerde JSON-bestand.</li><li>Ga terug naar ImgBed en importeer het onder serviceaccount <code>JSON</code> (optioneel).</li><li>Klik na succesvolle import op quota opvragen.</li></ol><p>Na import toont ImgBed de projectnaam van het serviceaccount. Bij het opvragen leest ImgBed Google monitoringgegevens en toont het aantal aanroepen van deze maand.</p><p>Kort gezegd:</p><table tabindex="0"><thead><tr><th>Item</th><th>Doel</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Voert OCR-herkenning uit.</td></tr><tr><td>Serviceaccount <code>JSON</code></td><td>Vraagt op hoeveel Google Vision-aanroepen zijn gebruikt.</td></tr><tr><td>Rol <code>Monitoring Viewer</code></td><td>Laat het serviceaccount gebruiksgegevens lezen.</td></tr></tbody></table><h2 id="een-baidu-paddleocr-token-ophalen" tabindex="-1">Een Baidu PaddleOCR-token ophalen <a class="header-anchor" href="#een-baidu-paddleocr-token-ophalen" aria-label="Permalink to &quot;Een Baidu PaddleOCR-token ophalen&quot;">​</a></h2><p>Baidu PaddleOCR vereist een access token.</p><p><img src="'+n+'" alt="PaddleOCR-token ophalen" loading="lazy"></p><p>Open het <code>API</code>-aanroepvenster op de Baidu PaddleOCR-pagina, klik om een token te krijgen en kopieer het.</p><p>Ga terug naar ImgBed, plak het in <code>PaddleOCR Token</code> en sla op.</p><h2 id="herkenning-starten" tabindex="-1">Herkenning starten <a class="header-anchor" href="#herkenning-starten" aria-label="Permalink to &quot;Herkenning starten&quot;">​</a></h2><p>Selecteer in Bestandsbeheer een afbeelding of documentscreenshot en klik op <code>OCR</code>.</p><p><img src="'+o+'" alt="OCR-herkenning" loading="lazy"></p><p>Kies in het venster de herkenningsdienst en het model.</p><p>Veelgebruikte PaddleOCR-modellen:</p><table tabindex="0"><thead><tr><th>Model</th><th>Beste keuze voor</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Aanbevolen standaard. Goed voor documenten, tabellen, formules, stempels en gemengde layouts.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Eenvoudige afbeeldingen, gewone tekst en lichte herkenning.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Meertalig, complexe afbeeldingen en inhoud met grafieken.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Complexere documentpagina&#39;s en layoutreconstructie.</td></tr></tbody></table><p>Weet je het niet zeker, begin dan met <code>PP-StructureV3</code>.</p><h2 id="geavanceerde-opties" tabindex="-1">Geavanceerde opties <a class="header-anchor" href="#geavanceerde-opties" aria-label="Permalink to &quot;Geavanceerde opties&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Optie</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Oriëntatiecorrectie</td><td>Gebruik wanneer de afbeelding gedraaid of scheef is.</td></tr><tr><td>Document afvlakken</td><td>Gebruik voor gefotografeerde documenten met kromming of perspectief.</td></tr><tr><td>Layoutdetectie</td><td>Gebruik wanneer je koppen, alinea&#39;s, tabellen en afbeeldingsstructuur wilt behouden.</td></tr><tr><td>Grafiekherkenning</td><td>Gebruik wanneer de afbeelding grafieken of complexe structuren bevat.</td></tr><tr><td><code>Markdown</code> verbeteren</td><td>Maakt geëxporteerde Markdown leesbaarder.</td></tr></tbody></table><p>Voor gewone screenshots houd je de opties beperkt. Voor documentscans schakel je meer documentgerichte opties in.</p><h2 id="resultaten-bekijken" tabindex="-1">Resultaten bekijken <a class="header-anchor" href="#resultaten-bekijken" aria-label="Permalink to &quot;Resultaten bekijken&quot;">​</a></h2><p>Wanneer herkenning klaar is, toont het venster het resultaat.</p><p>Je kunt het direct kopiëren of exportformaten kiezen.</p><p><img src="'+a+'" alt="PDF-herkenning" loading="lazy"></p><p>Voor documentpagina&#39;s kan geëxporteerde <code>PDF</code> de paginaweergave behouden en tegelijk tekst doorzoekbaar maken. Dat is handig voor archiveren van scans en later terugvinden van inhoud.</p><h2 id="exportformaat-kiezen" tabindex="-1">Exportformaat kiezen <a class="header-anchor" href="#exportformaat-kiezen" aria-label="Permalink to &quot;Exportformaat kiezen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Formaat</th><th>Beste keuze voor</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notities, documentatiesystemen en later bewerken.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Paginaweergave bewaren en scanresultaten archiveren.</td></tr><tr><td><code>Word (.docx)</code></td><td>Layout verder bewerken, tekst aanpassen en delen met anderen.</td></tr><tr><td>Alles exporteren</td><td>Slaat meerdere formaten en de oorspronkelijke afbeelding op, geschikt voor belangrijke archieven.</td></tr></tbody></table><p>Heb je alleen tekst nodig, exporteer dan Markdown.</p><p>Heb je paginaweergave nodig, gebruik dan PDF of Word.</p><h2 id="word-uitvoer" tabindex="-1">Word-uitvoer <a class="header-anchor" href="#word-uitvoer" aria-label="Permalink to &quot;Word-uitvoer&quot;">​</a></h2><p>Geëxporteerde Word-documenten kunnen met office-software worden geopend en bewerkt.</p><p><img src="'+d+`" alt="Word-resultaat" loading="lazy"></p><p>Sommige documenten bevatten herkende afbeeldingen, koppen en alinea&#39;s in de Word-uitvoer.</p><p>De kwaliteit hangt af van de scherpte van het origineel, de modelkeuze en de complexiteit van het document.</p><h2 id="beste-bestandstypen-voor-ocr" tabindex="-1">Beste bestandstypen voor OCR <a class="header-anchor" href="#beste-bestandstypen-voor-ocr" aria-label="Permalink to &quot;Beste bestandstypen voor OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Bestandstype</th><th>Aanbeveling</th></tr></thead><tbody><tr><td>Duidelijke screenshots</td><td>Direct herkennen.</td></tr><tr><td>Scans</td><td>Kies bij voorkeur <code>PP-StructureV3</code>.</td></tr><tr><td>Gefotografeerde documenten</td><td>Schakel oriëntatiecorrectie en documentafvlakking in.</td></tr><tr><td>Tabellen, formules, stempels</td><td>Gebruik bij voorkeur gestructureerde modellen.</td></tr><tr><td>Eenvoudige korte tekstafbeeldingen</td><td><code>PP-OCRv5</code> is meestal voldoende.</td></tr></tbody></table><p>Duidelijkere afbeeldingen met rechtere tekst leveren meestal betere resultaten op.</p><h2 id="veelvoorkomende-situaties" tabindex="-1">Veelvoorkomende situaties <a class="header-anchor" href="#veelvoorkomende-situaties" aria-label="Permalink to &quot;Veelvoorkomende situaties&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Situatie</th><th>Betekenis</th></tr></thead><tbody><tr><td>Herkenning mislukt</td><td>Controleer of het servicetoken of de key is opgeslagen.</td></tr><tr><td>Herkenning is traag</td><td>Complexe documenten en grote afbeeldingen kosten meer tijd.</td></tr><tr><td>Tabel is onvolledig</td><td>Probeer een gestructureerd model.</td></tr><tr><td>Tekst bevat fouten</td><td>Onscherpte, reflectie en scheefstand vergroten herkenningsfouten. Probeer een duidelijkere afbeelding.</td></tr><tr><td>Word-uitvoer bevat veel afbeeldingen</td><td>Gestructureerde modellen kunnen sommige herkende afbeeldingen behouden. Dat is normaal.</td></tr></tbody></table><h3 id="google-quota-opvraag-mislukt" tabindex="-1">Google quota-opvraag mislukt <a class="header-anchor" href="#google-quota-opvraag-mislukt" aria-label="Permalink to &quot;Google quota-opvraag mislukt&quot;">​</a></h3><p>Controleer:</p><ol><li>Serviceaccount-<code>JSON</code> is geïmporteerd.</li><li>Het serviceaccount heeft de rol <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> is ingeschakeld voor het project.</li></ol><p>Heb je alleen OCR nodig en geen gebruiksopvraag, dan kun je de serviceaccount-JSON negeren en alleen <code>Google Vision API Key</code> invullen.</p><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open System Settings</span></span>
<span class="line"><span>-&gt; Open Other Settings</span></span>
<span class="line"><span>-&gt; Vul OCR-servicegegevens in</span></span>
<span class="line"><span>-&gt; Sla op</span></span>
<span class="line"><span>-&gt; Ga terug naar Bestandsbeheer</span></span>
<span class="line"><span>-&gt; Selecteer een bestand en klik OCR</span></span>
<span class="line"><span>-&gt; Kies een model</span></span>
<span class="line"><span>-&gt; Wacht op herkenning</span></span>
<span class="line"><span>-&gt; Kopieer resultaten of exporteer Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const C=i(p,[["render",g]]);export{O as __pageData,C as default};
